#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=505,mod=1024523;
int n,m,dp[2][N][N];
string s1,s2;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s1>>s2;
	reverse(s1.begin(),s1.end());
	reverse(s2.begin(),s2.end());
	s1=" "+s1;
	s2=" "+s2;
//	cout<<s1<<"\n"<<s2<<"\n";
	dp[0][0][0]=1;
	for(int i=1;i<=n+m;i++)
	{
		for(int j=0;j<=n;j++)
		{
			for(int k=0;k<=n;k++)
			{
				dp[i%2][j][k]=0;
				if(s1[j]==s1[k]) dp[i%2][j][k]+=dp[(i-1)%2][j-1][k-1];
				if(s1[j]==s2[i-k]) dp[i%2][j][k]+=dp[(i-1)%2][j-1][k];
				if(s2[i-j]==s1[k]) dp[i%2][j][k]+=dp[(i-1)%2][j][k-1];
				if(s2[i-j]==s2[i-k]) dp[i%2][j][k]+=dp[(i-1)%2][j][k];
				dp[i%2][j][k]%=mod;
			}
		}
	}
	cout<<dp[(n+m)%2][n][n];
	return 0;
}
